package com.jdmedia.controller;
import com.jdmedia.model.*;import com.jdmedia.service.AppContext;import javafx.fxml.FXML;import javafx.scene.control.*;
public final class SummaryController {private static ConversionOptions options;private final AppContext context;@FXML private Label filesLabel,descriptionLabel,estimateLabel;@FXML private ComboBox<ConversionPreset> qualityBox;public SummaryController(AppContext context){this.context=context;}public static void setOptions(ConversionOptions value){options=value;}public static ConversionOptions options(){return options;}@FXML public void initialize(){filesLabel.setText(AnalysisController.media().size()+" archivo(s) listo(s) para convertir");qualityBox.getItems().setAll(ConversionPreset.values());qualityBox.setValue(fromCrf(options.crf()));qualityBox.valueProperty().addListener((o,a,b)->showEstimate(b));showEstimate(qualityBox.getValue());}private void showEstimate(ConversionPreset preset){long total=AnalysisController.media().stream().mapToLong(MediaFile::sizeBytes).sum();long estimated=Math.round(total*preset.estimatedRemaining());descriptionLabel.setText(preset.description()+". Se usará NVIDIA NVENC si está disponible para acelerar la conversión.");estimateLabel.setText("Estimación orientativa: "+size(total)+" → aproximadamente "+size(estimated)+" (ahorro estimado: "+size(total-estimated)+").");}@FXML private void start(){ConversionPreset p=qualityBox.getValue();options=new ConversionOptions("medium",p.crf(),options.audioStreamIndexes(),options.subtitles(),false);context.navigation().show("conversion-view.fxml");}@FXML private void back(){context.navigation().show("analysis-view.fxml");}private ConversionPreset fromCrf(int c){return c<=20?ConversionPreset.HIGH_QUALITY:c>=27?ConversionPreset.HIGH_COMPRESSION:ConversionPreset.BALANCED;}private String size(long b){return String.format("%.2f GB",b/1_073_741_824d);}}
